import React, { useContext, useEffect } from 'react';
import { AppContext } from '../context/AppContext';
import TaskCard from '../components/TaskCard';
import { getTasks, updateTask } from '../services/api';

const Dashboard = () => {
    const { userName, tasks, setTasks, userId, navigate } = useContext(AppContext);

    useEffect(() => {
        if (userId) {
            getTasks(userId)
                .then(res => setTasks(res.data))
                .catch(err => console.error("Failed to fetch tasks", err));
        }
    }, [userId, setTasks]);

    const dateStr = new Date().toLocaleDateString('en-IN', {
        weekday: 'long',
        day: 'numeric',
        month: 'long',
        year: 'numeric'
    });

    const getGreeting = () => {
        const hr = new Date().getHours();
        if (hr < 12) return 'Good morning';
        if (hr < 18) return 'Good afternoon';
        return 'Good evening';
    };

    // Normalize statuses for counting and grouping
    const normalizedTasks = tasks.map(t => {
        let nStatus = t.status;
        if (nStatus === 'done') nStatus = 'completed';
        if (nStatus === 'progress' || nStatus === 'submitted') nStatus = 'in_progress';
        if (nStatus === 'pending') nStatus = 'not_started';
        return { ...t, normalizedStatus: nStatus };
    });

    const doneCount = normalizedTasks.filter(t => t.normalizedStatus === 'completed').length;
    const progressCount = normalizedTasks.filter(t => t.normalizedStatus === 'in_progress').length;
    const notStartedCount = normalizedTasks.filter(t => t.normalizedStatus === 'not_started').length;
    const totalCount = tasks.length;
    const progressPct = totalCount ? (doneCount / totalCount) * 100 : 0;

    const handleStatusChange = async (index, newStatus) => {
        // Optimistic UI Update
        const newTasks = [...tasks];
        newTasks[index].status = newStatus;
        setTasks(newTasks);

        try {
            await updateTask(userId, index, newStatus);
        } catch (error) {
            console.error("Failed to update task status", error);
            // Could revert UI state here if needed
        }
    };

    return (
        <div style={{
            flex: 1,
            backgroundColor: 'var(--warm-white)',
            display: 'flex',
            flexDirection: 'column',
            paddingTop: 'var(--sat)',
            overflow: 'hidden',
            animation: 'slideUp 0.3s cubic-bezier(0.22, 1, 0.36, 1)'
        }}>
            <div className="scroll-container" style={{ flex: 1, padding: '14px 20px 100px' }}>

                {/* Header section */}
                <div style={{ marginBottom: '24px', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <div>
                        <h1 style={{
                            fontSize: 'clamp(24px, 6.5vw, 30px)',
                            color: 'var(--text-dark)',
                            marginBottom: '4px'
                        }}>
                            {getGreeting()}{userName ? `, ${userName}` : ''} 👋
                        </h1>
                        <div style={{ color: 'var(--text-light)', fontSize: '14px' }}>
                            {dateStr}
                        </div>
                    </div>
                    {/* Logout Button */}
                    <button
                        onClick={() => {
                            localStorage.clear();
                            window.location.reload();
                        }}
                        style={{
                            padding: '8px 12px',
                            backgroundColor: 'transparent',
                            color: 'var(--text-light)',
                            fontSize: '13px',
                            fontWeight: 600,
                            borderRadius: '8px',
                            border: '1px solid var(--border)',
                            cursor: 'pointer'
                        }}
                    >
                        Log Out
                    </button>
                </div>

                {/* Progress Card */}
                <div style={{
                    backgroundColor: 'var(--deep-teal)',
                    borderRadius: '20px',
                    padding: '24px',
                    color: '#fff',
                    position: 'relative',
                    overflow: 'hidden',
                    marginBottom: '20px',
                    boxShadow: 'var(--shadow-md)'
                }}>
                    <div style={{
                        position: 'absolute',
                        top: '-20px',
                        right: '-20px',
                        width: '150px',
                        height: '150px',
                        borderRadius: '50%',
                        backgroundColor: 'rgba(255,255,255,0.04)'
                    }} />

                    <div style={{
                        fontSize: '12px',
                        letterSpacing: '1px',
                        textTransform: 'uppercase',
                        color: 'rgba(255,255,255,0.6)',
                        marginBottom: '16px'
                    }}>
                        OVERALL PROGRESS
                    </div>

                    <div style={{ display: 'flex', alignItems: 'baseline', gap: '8px', marginBottom: '16px' }}>
                        <span style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: '48px', lineHeight: 1 }}>
                            {doneCount}
                        </span>
                        <span style={{ fontSize: '18px', color: 'rgba(255,255,255,0.6)' }}>
                            / {totalCount} done
                        </span>
                    </div>

                    {/* Progress Bar */}
                    <div style={{
                        height: '6px',
                        backgroundColor: 'rgba(255,255,255,0.1)',
                        borderRadius: '3px',
                        marginBottom: '12px',
                        position: 'relative',
                        overflow: 'hidden'
                    }}>
                        <div style={{
                            position: 'absolute',
                            top: 0,
                            left: 0,
                            height: '100%',
                            backgroundColor: 'var(--gold)',
                            borderRadius: '3px',
                            width: `${progressPct}%`,
                            transition: 'width 1s cubic-bezier(0.22, 1, 0.36, 1)'
                        }} />
                    </div>

                    <div style={{ fontSize: '13px', color: 'rgba(255,255,255,0.6)' }}>
                        {totalCount - doneCount} tasks remaining · est. 4–6 weeks
                    </div>
                </div>

                {/* Summary Bar */}
                <div style={{
                    display: 'flex',
                    gap: '8px',
                    marginBottom: '24px'
                }}>
                    <div style={{ flex: 1, backgroundColor: '#E8F5E9', padding: '12px', borderRadius: '12px', textAlign: 'center', color: '#2E7D32' }}>
                        <div style={{ fontSize: '20px', fontWeight: 700 }}>{doneCount}</div>
                        <div style={{ fontSize: '11px', fontWeight: 600 }}>Completed</div>
                    </div>
                    <div style={{ flex: 1, backgroundColor: '#E3F2FD', padding: '12px', borderRadius: '12px', textAlign: 'center', color: '#1565C0' }}>
                        <div style={{ fontSize: '20px', fontWeight: 700 }}>{progressCount}</div>
                        <div style={{ fontSize: '11px', fontWeight: 600 }}>In Progress</div>
                    </div>
                    <div style={{ flex: 1, backgroundColor: '#FFF3E0', padding: '12px', borderRadius: '12px', textAlign: 'center', color: '#E65100' }}>
                        <div style={{ fontSize: '20px', fontWeight: 700 }}>{notStartedCount}</div>
                        <div style={{ fontSize: '11px', fontWeight: 600 }}>Not Started</div>
                    </div>
                </div>

                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                    <h3 style={{ fontSize: '18px', fontWeight: 600, color: 'var(--text-dark)', fontFamily: 'DM Sans, sans-serif' }}>
                        All Tasks
                    </h3>
                </div>

                {tasks.map((task, idx) => (
                    <TaskCard
                        key={idx}
                        {...task}
                        status={task.status} // Pass un-normalized to let TaskCard handle if needed
                        onClick={() => {
                            if (task.name.includes('SBI')) navigate('guidance');
                        }}
                        onStatusChange={(newStatus) => handleStatusChange(idx, newStatus)}
                    />
                ))}

                {!tasks.length && (
                    <div style={{ padding: '32px', textAlign: 'center', color: 'var(--text-light)' }}>
                        Loading customized task list...
                    </div>
                )}

            </div>
        </div>
    );
};

export default Dashboard;
